// Astro 2.2.1 - PingSpoof.java
@Subscribe
public void onEvent(EventReceivePacket event) {
  if (event.getPacket() instanceof S00PacketKeepAlive) {
    event.setCancelled();
    S00PacketKeepAlive s00 = (S00PacketKeepAlive) event.getPacket();
    // Add FPS/2 offset to the ID to avoid simple pattern detection
    mc.getNetHandler().getNetworkManager().sendPacket(
      new C00PacketKeepAlive(s00.func_149134_c() + mc.getDebugFPS() / 2));
  }
}

