if (ep.isOutgoing() && ep.getPacket() instanceof C00PacketKeepAlive && mc.thePlayer.isEntityAlive()) {
  packetList.add(ep.getPacket());  // store in queue
  event.setCancelled(true);        // block immediate send
}
// On each game tick, flush packets that have aged past the delay threshold:
if (timer.delay(1000 * waitSeconds)) {
  // release packets in small batches to simulate real network
  mc.getNetHandler().getNetworkManager().sendPacketNoEvent(new C00PacketKeepAlive(10000));
}

// Tenacity 5.1 - Disabler.java
if(!timer.hasTimeElapsed(350)) {
